client_script:
frappe.web_form.on('load', function(){
  var user = (frappe.session && frappe.session.user) ? frappe.session.user : null;
  if (!user || user === 'Guest') return;

  var roles = (frappe.boot && frappe.boot.user && frappe.boot.user.roles) ? frappe.boot.user.roles : [];
  var can_select_any = roles.indexOf('Accounts Manager') !== -1 || roles.indexOf('System Manager') !== -1;


  frappe.call({
    method: 'frappe.client.get_value',
    args: {
      doctype: 'Employee',
      filters: { user_id: user, status: 'Active' },
      fieldname: ['name', 'employee_name']
    },
    callback: function(r){
      if (!r || !r.message) return;
      if (!frappe.web_form.doc.caissiere) {
        frappe.web_form.set_value('caissiere', r.message.name);
      }
      if (r.message.employee_name && !frappe.web_form.doc.caissiere_name) {
        frappe.web_form.set_value('caissiere_name', r.message.employee_name);
      }
      if (!can_select_any) {
        frappe.web_form.set_df_property('caissiere', 'read_only', 1);
      }

      setTimeout(function() {
        if (window.kyaRestructureForm) window.kyaRestructureForm();
      }, 150);
    }
  });

  // Recalcul client: solde final + totaux
  function recompute() {
    var rows = (frappe.web_form.doc.lignes || []);
    var solde = parseFloat(frappe.web_form.doc.solde_precedent || 0);
    var te = 0, ts = 0;
    rows.forEach(function(r){
      var e = parseFloat(r.entree || 0);
      var s = parseFloat(r.sortie || 0);
      te += e; ts += s;
      solde += e - s;
      r.solde = solde;
    });
    frappe.web_form.set_value('total_entrees', te);
    frappe.web_form.set_value('total_sorties', ts);
    frappe.web_form.set_value('solde_final', parseFloat(frappe.web_form.doc.solde_precedent || 0) + te - ts);
  }
  frappe.web_form.after_save = recompute;
});
